// Caso: Rotar arreglo k | Nivel: Intermedio | Categoría: Arrays

public static class Solution {
  public static int[] Solve(int[] arr, int k) {
    int n = arr.Length;
    if (n == 0) return new int[0];
    int r = ((k % n) + n) % n;
    var outArr = new int[n];
    for (int i=0;i<n;i++) outArr[(i + r) % n] = arr[i];
    return outArr;
  }
}

