// C0666 · Merge sort (Intermedio, Algoritmos)
public static int[] Solve(int[] arr){
  if(arr.Length<=1) return arr;
  int mid = arr.Length/2;
  int[] left = arr[..mid];
  int[] right= arr[mid..];
  left = Solve(left); right = Solve(right);
  var outp = new int[arr.Length];
  int i=0,j=0,k=0;
  while(i<left.Length && j<right.Length){
    outp[k++] = (left[i] <= right[j]) ? left[i++] : right[j++];
  }
  while(i<left.Length) outp[k++] = left[i++];
  while(j<right.Length) outp[k++] = right[j++];
  return outp;
}

