// C0669 · LRU cache (Intermedio, Algoritmos)
using System.Collections.Generic;

public class LRU<K,V> {
  private readonly int cap;
  private readonly LinkedList<K> order = new();
  private readonly Dictionary<K, (V val, LinkedListNode<K> node)> map = new();

  public LRU(int cap){ this.cap = cap; }

  public V? Get(K key){
    if(!map.TryGetValue(key, out var e)) return default;
    order.Remove(e.node);
    order.AddLast(e.node);
    return e.val;
  }

  public void Put(K key, V val){
    if(map.TryGetValue(key, out var e)){
      order.Remove(e.node);
      order.AddLast(e.node);
      map[key] = (val, e.node);
      return;
    }
    var node = order.AddLast(key);
    map[key] = (val, node);
    if(map.Count > cap){
      var oldest = order.First!.Value;
      order.RemoveFirst();
      map.Remove(oldest);
    }
  }
}

